import React from 'react';

const NoteCard = ({ note, onOpenModal }) => {


  return (
    <div className="bg-white rounded-lg shadow-md p-4 hover:shadow-lg transition-shadow duration-200">
      <h3 className="text-lg font-semibold text-gray-800 mb-2">{note.title}</h3>
      <p className="text-gray-600 mb-3">{previewContent}</p>
      <p className="text-sm text-gray-500 mb-4">Created: {formattedDate}</p>
      <button
        onClick={() => onOpenModal(note)} // Opens the modal with this note
        className="w-full bg-indigo-600 text-white py-2 px-4 rounded-lg font-semibold hover:bg-indigo-700 transition-colors duration-200"
      >
        View/Edit Note
      </button>
    </div>
  );
};

export default NoteCard;
